function solve(n, edges, k) {
    edges.sort((a, b) => a[2] - b[2]);
    const maxW = edges.length === 0 ? 0 : edges[edges.length - 1][2];
    let low = 0;
    let high = maxW;

    while (low < high) {
        const mid = Math.floor((low + high) / 2);
        if (isPossible(n, edges, mid, k)) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }

    return low;

    function isPossible(n, edges, X, k) {
        const parent = Array(n).fill(0).map((_, i) => i);
        const rank = Array(n).fill(0);
        let count = n;

        function find(x) {
            if (parent[x] !== x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        for (const [u, v, w] of edges) {
            if (w <= X) {
                const rootU = find(u);
                const rootV = find(v);
                if (rootU !== rootV) {
                    if (rank[rootU] < rank[rootV]) {
                        parent[rootU] = rootV;
                    } else {
                        parent[rootV] = rootU;
                        if (rank[rootU] === rank[rootV]) {
                            rank[rootU]++;
                        }
                    }
                    count--;
                }
            }
        }

        return count <= k;
    }
}

