            if (parent[x] !== x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        for (const [u, v, w] of edges) {
            if (w <= X) {
                const rootU = find(u);
                const rootV = find(v);
                if (rootU !== rootV) {
                    if (rank[rootU] < rank[rootV]) {
                        parent[rootU] = rootV;
                    } else {
                        parent[rootV] = rootU;
                        if (rank[rootU] === rank[rootV]) {
                            rank[rootU]++;
                        }
                    }
                    count--;
                }
            }
        }

        return count <= k;
    }
